def test_start_blocks_until_ready(fake_ws_and_http: Any) -> None:
    client = AgentPulseClient(_config())
    try:
        client.start()
        assert client.connection_state() in (
            ConnectionState.CONNECTED,
            ConnectionState.CONNECTING,
        )
    finally:
        client.stop()


def test_marshaler_redirects_callbacks(fake_ws_and_http: Any) -> None:
    """Marshaler-supplied function receives every callback dispatch."""
    queue: list[Any] = []
    cond = threading.Condition()

    def marshaler(fn: Any) -> None:
        with cond:
            queue.append(fn)
            cond.notify_all()

    client = AgentPulseClient(_config(), marshaler=marshaler)
    try:
        client.start()
        client.on_change(lambda: None)
        client.refresh()
        with cond:
            cond.wait(timeout=2.0)
        for fn in queue:
            fn()
    finally:
        client.stop()


